const data = $input.first().json;

const clima = data.clima_hoy;
const combos = data.combos_top || [];
const bajos = data.productos_bajos || [];
const clima_x_prod = data.efecto_clima || [];
const tendencia = data.tendencia_ultimas_semanas || [];
const instruccionExtra = data.instruccion_extra || '';

const climaTexto = `Hoy en Villa Carlos Paz: ${clima.descripcion}, temp ${clima.temp_min}°-${clima.temp_max}° (media ${clima.temp_media}°), lluvia: ${clima.lluvia_mm}mm.`;

const combosTexto = combos.slice(0, 5).map(c =>
  `- ${c.producto_a} + ${c.producto_b}: salen juntos en el ${c.pct_ordenes}% de las órdenes (${c.veces_juntos} veces)`
).join('\n');

const bajosTexto = bajos.slice(0, 6).map(p =>
  `- ${p.descripcion}: esta semana ${p.unidades_ultima_semana} unidades (promedio histórico ${p.promedio_semanal}, variación ${p.variacion_pct}%)`
).join('\n');

const rangoHoy = clima.temp_media < 10 ? 'frio' : clima.temp_media <= 18 ? 'fresco' : 'calor';
const lluviaHoy = clima.lluvia_mm > 1 ? 'lluvia' : 'sin_lluvia';
const efectoHoy = clima_x_prod
  .filter(e => e.rango_temp === rangoHoy && e.condicion_lluvia === lluviaHoy)
  .map(e => `- ${e.descripcion}: promedio ${e.promedio_unidades} unidades en días ${rangoHoy} con ${lluviaHoy}`)
  .join('\n');

const semanas = [...new Set(tendencia.map(t => t.semana))].sort().reverse();
const ultSemana = tendencia.filter(t => t.semana === semanas[0]);
const antSemana = tendencia.filter(t => t.semana === semanas[1]);
const tendenciaTexto = ultSemana.slice(0, 8).map(p => {
  const ant = antSemana.find(a => a.descripcion === p.descripcion);
  const var_pct = ant ? Math.round((p.unidades - ant.unidades) / ant.unidades * 100) : null;
  return `- ${p.descripcion}: ${p.unidades} unidades${var_pct !== null ? ` (${var_pct > 0 ? '+' : ''}${var_pct}% vs semana anterior)` : ''}`;
}).join('\n');

const instruccionTexto = instruccionExtra
  ? `**INSTRUCCIÓN ESPECIAL DEL DÍA:**\n${instruccionExtra}\n\n`
  : '';

const prompt = `Sos el encargado de marketing de PizzaLibre, una pizzería en Villa Carlos Paz, Argentina. Tu tarea es generar EXACTAMENTE 4 propuestas de promociones atractivas y DISTINTAS entre sí, basadas en los datos reales de ventas.

${instruccionTexto}**CLIMA DE HOY:**
${climaTexto}

**COMBOS MÁS FRECUENTES (productos que los clientes piden juntos):**
${combosTexto}

**PRODUCTOS BAJOS ESTA SEMANA (candidatos a promocionar):**
${bajosTexto}

**EFECTO DEL CLIMA EN VENTAS DE HOY (condición: ${rangoHoy}, ${lluviaHoy.replace('_', ' ')}):**
${efectoHoy}

**TENDENCIA ÚLTIMA SEMANA:**
${tendenciaTexto}

**FORMATO DE RESPUESTA — MUY IMPORTANTE:**
Respondé ÚNICAMENTE con un array JSON válido con exactamente 4 objetos. Sin texto antes ni después. Sin markdown. Solo el JSON.

[
  {
    "nombre": "Nombre creativo de la promo",
    "productos": "Listado de productos incluidos",
    "razon": "Por qué tiene sentido según los datos (1 línea)",
    "beneficio": "Descuento o beneficio sugerido"
  }
]

Cada promo debe combinar al menos 2 productos. Variá los enfoques: una basada en clima, una en combo frecuente, una en producto bajo, una creativa. Español rioplatense, tono comercial y amigable.`;

return [{ json: { prompt, clima_hoy: climaTexto } }];

const response = $input.first().json;
const raw = response.message?.content || response.choices?.[0]?.message?.content || '[]';
const clima = $('Preparar prompt').first().json.clima_hoy;

let promos;
try {
  promos = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/\[.*\]/s);
  promos = match ? JSON.parse(match[0]) : [];
}

return promos.map(p => ({
  json: {
    nombre_promo: p.nombre,
    productos: p.productos,
    razon: p.razon,
    beneficio: p.beneficio,
    texto_promo: `**${p.nombre}**\n\nProductos: ${p.productos}\n\nPor qué: ${p.razon}\n\nBeneficio: ${p.beneficio}`,
    clima_hoy: clima
  }
}));
